const user = $('Normalize Message Input').first().json;
const ctx = $('Build AI Context').first().json.docContext || '';
const prompt = [
  'You extract booking details from WhatsApp messages.',
  'Return only valid minified JSON. No markdown. No explanation.',
  '{"bookingIntent":boolean,"name":"","email":"","dateText":"","timeText":"","timezone":"","notes":""}',
  '',
  'User message:',
  user.body,
  '',
  'Business context:',
  ctx
].join('\n');
return [{ json: { extractorPrompt: prompt } }];

let raw = $('Booking Information Agent').first().json.output || '';
const match = raw.match(/\{[\s\S]*\}/);
let obj = { bookingIntent: false, name: '', email: '', dateText: '', timeText: '', timezone: 'Asia/Kolkata', notes: '' };
if (match) {
  try { obj = { ...obj, ...JSON.parse(match[0]) }; } catch (e) {}
}
obj.bookingIntent = !!obj.bookingIntent;
obj.name = obj.name || $('Normalize Message Input').first().json.name || '';
obj.email = obj.email || '';
obj.dateText = obj.dateText || '';
obj.timeText = obj.timeText || '';
obj.timezone = obj.timezone || 'Asia/Kolkata';
obj.notes = obj.notes || '';
return [{ json: obj }];

const { dateText, timeText, timezone, bookingIntent, email, name, notes } = $json;
function normalizeDate(d) {
  if (!d) return '';
  const t = d.trim().toLowerCase();
  const now = new Date();
  const pad = n => String(n).padStart(2, '0');
  if (t === 'today') return `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
  if (t === 'tomorrow') {
    const x = new Date(now.getTime() + 86400000);
    return `${x.getFullYear()}-${pad(x.getMonth()+1)}-${pad(x.getDate())}`;
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  if (/^\d{1,2}[\/\-]\d{1,2}[\/\-]\d{2,4}$/.test(t)) {
    const [dd, mm, yy] = t.split(/[\/\-]/);
    const year = yy.length === 2 ? '20' + yy : yy;
    return `${year}-${pad(mm)}-${pad(dd)}`;
  }
  const weekdays = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
  if (weekdays.includes(t)) {
    const target = weekdays.indexOf(t);
    const current = now.getDay();
    let diff = (target - current + 7) % 7;
    if (diff === 0) diff = 7;
    const x = new Date(now.getTime() + diff * 86400000);
    return `${x.getFullYear()}-${pad(x.getMonth()+1)}-${pad(x.getDate())}`;
  }
  return '';
}
function normalizeTime(t) {
  if (!t) return '';
  const x = t.trim().toLowerCase();
  if (x.includes('morning')) return '10:00';
  if (x.includes('afternoon')) return '15:00';
  if (x.includes('evening')) return '18:00';
  const m = x.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)?/);
  if (!m) return '';
  let hour = parseInt(m[1], 10);
  const min = m[2] || '00';
  const ampm = m[3];
  if (ampm === 'pm' && hour < 12) hour += 12;
  if (ampm === 'am' && hour === 12) hour = 0;
  return `${String(hour).padStart(2,'0')}:${min}`;
}
const dateISO = normalizeDate(dateText);
const timeISO = normalizeTime(timeText);
const startISO = (dateISO && timeISO) ? `${dateISO}T${timeISO}:00.000Z` : '';
const canAttemptBooking = !!(bookingIntent && name && email && startISO);
return [{ json: { bookingIntent, name, email, notes, timezone, dateText, timeText, dateISO, timeISO, startISO, canAttemptBooking } }];

const username = 'CAL_USERNAME';
const eventSlug = '30min';
const link = `https://cal.com/${username}/${eventSlug}`;
const missing = [];
const p = $('Normalize Date and Time').first().json;
if (!p.name) missing.push('name');
if (!p.email) missing.push('email');
if (!p.dateISO) missing.push('date');
if (!p.timeISO) missing.push('time');
let answer = '';
if ($('Parse Booking Data').first().json.bookingIntent) {
  answer = missing.length
    ? `To book your meeting, please send your ${missing.join(', ')}. Or use this booking link: ${link}`
    : `I could not confirm that slot automatically. Please use this booking link to choose an available time: ${link}`;
} else {
  answer = '';
}
return [{ json: { answer, intent: 'booking_link_or_missing_fields' } }];

const msg = $json.messages?.[0] || {};
const contact = $json.contacts?.[0] || {};
const tsSec = Number(msg.timestamp || 0);
const tsMs = tsSec * 1000;
const withinWindow = tsSec > 0 && (Date.now() - tsMs) < 24 * 60 * 60 * 1000;
const body = (msg.text?.body || '').trim();
const from = msg.from || contact.wa_id || '';
const name = contact.profile?.name || '';
return [{ json: { withinWindow, body, from, name, raw: $json } }];

const doc = $json;
let text = doc.content || '';
if (Array.isArray(doc.body?.content)) {
  const runs = [];
  for (const block of doc.body.content) {
    const paras = block.paragraph?.elements || [];
    for (const el of paras) {
      const t = el.textRun?.content || '';
      if (t.trim()) runs.push(t.replace(/\n+/g, ' ').trim());
    }
  }
  text = runs.join(' ').replace(/\s+/g, ' ').trim();
}
const MAX_CHARS = 3500;
if (text.length > MAX_CHARS) text = text.slice(0, MAX_CHARS) + ' ...';
return [{ json: { docContext: text } }];

let answer = '';
let intent = 'support';
const bookingIntent = $('Parse Booking Data').first().json.bookingIntent;

try {
  const r = $('Post Cal Booking').first().json;
  const statusCode = r.statusCode || 200;
  if (statusCode >= 200 && statusCode < 300) {
    const d = r.data || r;
    const uid = d.uid || d.id || '';
    const start = d.start || d.startTime || $('Normalize Date and Time').first().json.startISO || '';
    answer = `Your meeting is booked. Booking ID: ${uid}. Time: ${start}.`;
    intent = 'booking_confirmed';
  } else if (statusCode === 400 || statusCode === 409) {
    answer = $('Handle Booking Failure').first().json.answer;
    intent = 'booking_slot_unavailable';
  }
} catch (e) {}

if (!answer) {
  if (bookingIntent) {
    try {
      const fallback = $('Handle Booking Failure').first().json.answer;
      if (fallback) {
        answer = fallback;
        intent = $('Handle Booking Failure').first().json.intent;
      }
    } catch (e) {}
  }
}

if (!answer) {
  try {
    answer = $('General Support Agent').first().json.output || 'Sorry, I could not process that right now.';
    intent = 'support';
  } catch (e) {
    answer = 'Sorry, I could not process that right now.';
  }
}

answer = answer.replace(/[*_~`]+/g, '').replace(/\n{3,}/g, '\n\n').trim();
if (answer.length > 600) answer = answer.slice(0, 597) + '...';
return [{ json: { answer, intent } }];
